a = 0;
b = 1;
e = 0.0000000001;
ya = exp(a) + 3*a - 2;
yb = exp(b) + 3*b - 2;
while abs(a-b) > e
  c = (a+b)/2;
  yc = exp(c) + 3*c - 2;
  if ya*yc < 0
    b = c;
  else
    a = c;
    ya = exp(a) + 3*a - 2;
  end
end
