x0 = 0.5;
e = 0.0000000001;
y = cos(x0) - x0^3;
yp = -sin(x0) - 3*x0^2;
x1 = x0 - y/yp;
while abs(x1-x0) > e
  x0 = x1;
  y = cos(x0) - x0^3;
  yp = -sin(x0) - 3*x0^2;
  x1 = x0 - y/yp;
end
fprintf('racine x=%f\n', x1);

a = 0; b = 1; M = 100;
H = (b-a)/M;
I = 0;
for k = 1:M
  x = a + (k-1)*H;
  I = I + H*f(x);
end
disp(['I = ', num2str(I)]);

a = 0; b = 1; M = 100;
H = (b-a)/M;
I = 0;
for k = 1:M-1
  I = I + H*f(a + k*H);
end
I = I + H*(f(a)+f(b))/2;
disp(['I = ', num2str(I)]);

a = 0; b = 1; M = 100;
H = (b-a)/M;
I = 0;
for k = 1:M
  xk = a + k*H;
  xbar = (a + (k-1)*H + xk)/2;
  S = (f(a+(k-1)*H) + 4*f(xbar) + f(xk))*H/6;
  I = I + S;
end
disp(['I = ', num2str(I)]);
